eserialize(JSONObject responseBody) {        InferenceParse parseResult = new InferenceParse(responseBody.getString(KEY_REASON),                InferenceConfidence.parse(responseBody.getString(KEY_CONFIDENCE)));        JSONArray targetColumns = responseBody.getJSONArray(KEY_TARGET_COLUMNS);        JSONObject targetCol = null;        if (CollectionUtils.isNotEmpty(targetColumns)) {            for (int i = 0; i < targetColumns.size(); i++) {                targetCol = targetColumns.getJSONObject(i);                parseResult.addTargetProp(new TargetProperty(targetCol.getString(KEY_TABLE),                        targetCol.getString(KEY_COLUMN)));            }        }        return parseResult;    }    //    //   b.addProperty("confidence", TISJsonSchema.FieldType.String, "置信度")    //            .setValEnums("high", "medium", "low");    //                    b.addProperty("reason", TISJsonSchema.FieldType.String, "推断理由");    private final String reason;    private final InferenceConfidence confidence;    private final List<TargetProperty> targetProps = Lists.newArrayList();    public InferenceParse(String reason, InferenceConfidence confidence) {        this.reason = reason;        this.confidence = confidence;    }    static void addTargetColumns2Schema(TISJsonSchema.Builder b) {        // String targetColumns = "targetColumns";        TISJsonSchema.Builder targetColumnsBuilder = TISJsonSchema.Builder.create(KEY_TARGET_COLUMNS,                Optional.empty());        targetColumnsBuilder.addProperty(KEY_TABLE, TISJsonSchema.FieldType.String, "指定user prompt中的table名称");        targetColumnsBuilder.addProperty(KEY_COLUMN, TISJsonSchema.FieldType.String, "指定user prompt中的table"                + "的column名");        b.addProperty(KEY_TARGET_COLUMNS, TISJsonSchema.FieldType.Array, "指定目标作用的目标列（target columns）")                .setItems(targetColumnsBuilder.build());    }    public String getReason() {        return reason;    }    public InferenceConfidence getConfidence() {        return confidence;    }    public void addTargetProp(TargetProperty targetProperty) {        this.targetProps.add(targetProperty);    }    public List<TargetProperty> getTargetProps() {        return this.targetProps;    }    public enum InferenceConfidence {        High("high"), Medium("medium"), Low("how");        private final String token;        private static InferenceConfidence parse(String token) {            for (InferenceConfidence c : InferenceConfidence.values()) {                if (c.token.equals(token)) {                    return c;                }            }            throw new IllegalStateException("illegal token:" + token);        }        private InferenceConfidence(String token) {            this.token = token;        }    }    public record TargetProperty(String objectType, String property) {        public TargetProperty(String objectType, String property) {            this.objectType = Objects.requireNonNull(objectType);            this.property = Objects.requireNonNull(property);        }        @Override        public String toString() {            return "{" +                    "objectType='" + objectType + '\'' +                    ", property='" + property + '\'' +                    '}';        }    }}